addEventListener("fetch", event => {
  const url = new URL(event.request.url);
  let origin = "https://example.com"; // Replace with your backend service's origin

  if (url.origin === origin) {
    event.respondWith(handleRequest(event.request));
  } else {
    event.respondWith(new Response("Not found", { status: 404 }));
  }
});

async function handleRequest(request) {
  const url = new URL(request.url);
  let headers = {};

  // Set CORS headers for maximum compatibility during development
  if (url.origin === "http://localhost:3000" || url.origin === "https://staging.example.com") {
    headers["Access-Control-Allow-Origin"] = "*";
  }

  // Forward the request to the backend service
  const response = await fetch(url, {
    method: request.method,
    headers: headers,
    body: request.body,
  });

  return new Response(response.body, {
    status: response.status,
    headers: response.headers,
  });
}